def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            score -= 200 * (ratio - 4)**4 + 50 * np.log1p(ratio-4)
        elif 3 < ratio <= 4:
            for a in range(3):
                score -= (30 + 10*a) * (ratio - 3)**(2 + a/2)
            score += 5 * np.sin(ratio * 7)
        elif 2 < ratio <= 3:
            for b in range(1,5):
                score -= (10 * b) * (ratio - 2)**(b*0.5)
            score += np.cos(ratio * 12) * 20
        elif 1 < ratio <= 2:
            if ratio < 1.5:
                for c in range(1, 4):
                    val = (ratio - 1)**c * np.exp(-c * ratio)
                    score += (-1)**c * 15 * val
            else:
                score -= 40 * ((ratio - 1)**2.5)
                score += 10 * np.cos(ratio * 5)
        else:
            intervals = [0.1, 0.2, 0.35, 0.5, 0.7, 0.85, 1.0]
            weights = [50, 40, 30, 20, 10, 5, 1]
            added = False
            for idx, threshold in enumerate(intervals):
                if ratio < threshold:
                    score += weights[idx] / max((threshold - ratio), 1e-12)
                    added = True
                    break
            if not added:
                for d in range(3):
                    score += np.sin(ratio * np.pi * (d+1)) * (7 - d)
                score += 25 * (1 - ratio)
        penalty = 0
        for x in range(1, 7):
            term = ((-1)**(x+1)) * (ratio ** (2 * x)) / (x**2 + 1)
            if x % 3 == 0:
                penalty += term * np.log1p(x * ratio + 1)
            else:
                penalty += term / (1 + np.exp(-x*ratio))
        score += penalty
        if item > capacity:
            score -= 120
            for m in range(1, 6):
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.6) / (m**1.1)
                if mod_val > capacity * (0.6 - 0.1 * m):
                    score -= 15 / m
        else:
            fill_ratio = (capacity - item) / capacity
            if fill_ratio < 0.15:
                score += 30
                for n in range(4):
                    score += (capacity - item) * np.cos((n+1)*ratio*np.pi*1.2) / (n+1)
                    score += np.sin((n+1)*ratio*np.pi*0.7) * 3
            elif fill_ratio < 0.5:
                score += 10 * np.exp(-3 * ratio)
                for p in range(1,5):
                    score += np.tanh(ratio * p) * (7 - p)
            else:
                if ratio < 0.3:
                    for q in range(5):
                        score -= 8 * np.exp(-ratio*12) * (q+1)
                        score += np.cos(ratio * 15 * (q+1)) / (q+2)
                else:
                    score += 5 * np.sin(ratio * 10)
                    for r in range(3):
                        score += (r+1)**2 / (1 + ratio*(r+1))
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio) ** 2
        elif capacity % 4 == 0:
            score -= 6 * np.sqrt(abs(ratio - 0.4))
            for s in range(1,5):
                if (capacity + s) % 3 == 0:
                    score += 0.3 * s / (1 + ratio * s)
        else:
            for t in range(1,7):
                if (capacity + t) % 2 == 1:
                    score += 0.7 * t / (1 + ratio * (t ** 0.5))
                else:
                    score -= 0.4 * t * ratio / (t + ratio)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
